# Merge all lessons needing all 4 arrays
needs_all_four.update(remaining_lessons)
needs_all_four.update(more_lessons)

# Now process the file
lines = content.split('\n')

# For lessons WITH riskFactors: insert diagnostics, management, nursingActions after riskFactors line, before signs
for lesson_id, arrays in already_has_rf.items():
    pattern = f'  "{lesson_id}":'
    found = False
    for i, line in enumerate(lines):
        if pattern in line:
            # Find the riskFactors line
            for j in range(i, min(i+20, len(lines))):
                if 'riskFactors:' in lines[j] and 'riskFactors?:' not in lines[j]:
                    # Insert after riskFactors line
                    insert_text = arrays["diagnostics"] + "\n" + arrays["management"] + "\n" + arrays["nursingActions"]
                    lines.insert(j+1, insert_text)
                    found = True
                    break
            break
    if not found:
        print(f"WARNING: Could not find riskFactors for {lesson_id}")

# For lessons WITHOUT riskFactors: insert all 4 arrays after cellular line, before signs
for lesson_id, arrays in needs_all_four.items():
    pattern = f'  "{lesson_id}":'
    found = False
    for i, line in enumerate(lines):
        if pattern in line:
            # Find the signs line
            for j in range(i, min(i+30, len(lines))):
                if '    signs:' in lines[j] and 'signs.' not in lines[j]:
                    # Insert before signs line
                    insert_text = arrays["riskFactors"] + "\n" + arrays["diagnostics"] + "\n" + arrays["management"] + "\n" + arrays["nursingActions"]
                    lines.insert(j, insert_text)
                    found = True
                    break
            break
    if not found:
        print(f"WARNING: Could not find insertion point for {lesson_id}")

# Write the file back
new_content = '\n'.join(lines)
with open('client/src/pages/lesson-detail.tsx', 'w') as f:
    f.write(new_content)

print("Done! All arrays inserted.")
print(f"Original lines: {len(content.split(chr(10)))}")
print(f"New lines: {len(new_content.split(chr(10)))}")
